// VALEURS A VERIFIER AVANT D'EXECUTER
// currentCumul : lire sur NanoPi
//   dbus -y com.victronenergy.pvinverter.cgwacs_ttyUSB0_mb2 /Ac/Energy/Forward GetValue
// totalVictron : valeur Solaire affichee dans Venus OS (MPPT + PVInverter)

const currentCumul = 587.2;   // kWh cumule PVInverter (NanoPi)
const totalVictron  = 3.9;    // kWh Solaire Victron (MPPT + PVInv)

const mpptToday   = global.get('mppt_yield_today') || 0;
const pvinvToday  = Math.max(0, parseFloat((totalVictron - mpptToday).toFixed(3)));
const newBaseline = parseFloat((currentCumul - pvinvToday).toFixed(3));
const total       = parseFloat((mpptToday + pvinvToday).toFixed(3));

global.set('pvinv_baseline',    newBaseline);
global.set('pvinv_yield_today', pvinvToday);
global.set('total_yield_today', total);

node.warn('Baseline fixee: ' + newBaseline + ' kWh | MPPT: ' + mpptToday.toFixed(2) + ' | PVInv: ' + pvinvToday.toFixed(2) + ' | Total: ' + total.toFixed(2) + ' kWh');
node.status({fill:'green', shape:'dot', text:'Total=' + total.toFixed(2) + ' kWh OK'});
return msg;
